mapper.insert:
INSERT INTO SPACE (
    space_no, host_id, category_no, space_name, 
    biz_reg_num, address, detail_addr, region, 
    bank_name, account_no, account_holder
) VALUES (
    #{spaceNo}, #{hostId}, #{categoryNo}, #{spaceName}, 
    #{bizRegNum}, #{address}, #{detailAddr}, #{region}, 
    #{bankName}, #{accountNo}, #{accountHolder}
)

INSERT INTO SPACE_IMAGE (
    image_no, space_no, file_url
) VALUES (
    SEQ_SPACE_IMAGE.NEXTVAL, #{spaceNo}, #{fileUrl}
)

INSERT INTO SELECTED_SPACE_OPTION (
    sso_no, option_no, unit_no
) VALUES (
    SEQ_SELECTED_SPACE_OPTION.NEXTVAL, #{optionNo}, #{unitNo}
)

INSERT INTO SPACE_UNIT (
    unit_no, space_no, title, price_per_hour, 
    max_capacity, description, thumbnail_url
) VALUES (
    #{unitNo}, #{spaceNo}, #{title}, #{pricePerHour}, 
    #{maxCapacity}, #{description}, #{thumbnailUrl}
)

INSERT INTO SPACE_POLICY (
    policy_no, unit_no, min_hours, cancel_limit_hr, cleaning_fee
) VALUES (
    SEQ_SPACE_POLICY.NEXTVAL, #{unitNo}, #{minHour}, #{cancelLimitHr}, #{cleaningFee}
)

INSERT INTO SPACE_UNIT_TIME (
    unit_time_no, unit_no, day_of_week, open_time, close_time
) VALUES (
    SEQ_SPACE_UNIT_TIME.NEXTVAL, #{unitNo}, #{dayOfWeek}, #{openTime}, #{closeTime}
)
